<?php
namespace App\Http\Controllers\Admin; use App\Http\Controllers\Controller; use App\Models\TermsConditionSection; use Illuminate\Http\Request; use Illuminate\Support\Str;
class TermsConditionSectionController extends Controller { public function index(){return view('admin.terms-condition-sections.index',['sections'=>TermsConditionSection::orderBy('sort_order')->get()]);}public function create(){return view('admin.terms-condition-sections.form',['section'=>new TermsConditionSection]);}public function store(Request $r){TermsConditionSection::create($this->data($r));return redirect()->route('admin.terms-condition-sections.index')->with('success','Terms section added.');}public function edit(TermsConditionSection $termsConditionSection){return view('admin.terms-condition-sections.form',['section'=>$termsConditionSection]);}public function update(Request $r,TermsConditionSection $termsConditionSection){$termsConditionSection->update($this->data($r,$termsConditionSection));return redirect()->route('admin.terms-condition-sections.index')->with('success','Terms section updated.');}public function destroy(TermsConditionSection $termsConditionSection){$termsConditionSection->delete();return back()->with('success','Terms section deleted.');}private function data(Request $r,?TermsConditionSection $s=null):array{$d=$r->validate(['title'=>'required|string|max:255','subtitle'=>'nullable|string|max:255','icon_class'=>'nullable|string|max:100','content'=>'required|string','sort_order'=>'nullable|integer']);$d['slug']=Str::slug($d['title']);if(TermsConditionSection::where('slug',$d['slug'])->when($s,fn($q)=>$q->where('id','!=',$s->id))->exists())$d['slug'].='-'.uniqid();$d['icon_class']=$d['icon_class']?:'bi bi-file-earmark-text';$d['status']=$r->boolean('status');$d['sort_order']=$d['sort_order']??0;return $d;}}
